# scripts/check_version_policy.py
# Run in CI before every production deployment
# Exits non-zero if any approved-version policy is violated

import subprocess, sys, json, re

APPROVED = {
    "python": ["3.11", "3.12"],
    "torch":  ["2.3", "2.4"],
    "onnxruntime": ["1.17", "1.18"],
    "fastapi": ["0.109", "0.110", "0.111", "0.112", "0.113", "0.114", "0.115"],
    "openai":  None,   # None = all current releases approved (track separately)
    "langchain": ["0.2"],
}

NOT_APPROVED_PATTERNS = [
    ("python", r"^3\.[0-9]$"),          # 3.x with single digit minor
    ("torch",  r"^2\.0|^1\."),         # 2.0 or any 1.x
    ("langchain", r"^0\.0\."),          # 0.0.x (legacy v1 API)
]

def check_python_version() -> list[str]:
    v = sys.version_info
    minor = f"{v.major}.{v.minor}"
    if minor not in APPROVED["python"]:
        return [f"Python {minor} is not in approved list {APPROVED['python']}"]
    return []

def check_pip_packages() -> list[str]:
    result = subprocess.run(
        ["pip", "list", "--format=json"], capture_output=True, text=True
    )
    packages = {p["name"].lower(): p["version"] for p in json.loads(result.stdout)}
    violations = []

    for pkg, approved_minors in APPROVED.items():
        if pkg == "python" or approved_minors is None:
            continue
        installed = packages.get(pkg)
        if not installed:
            continue
        installed_minor = ".".join(installed.split(".")[:2])
        if installed_minor not in approved_minors:
            violations.append(
                f"{pkg}=={installed} (minor {installed_minor}) not in approved {approved_minors}"
            )

    for pkg, pattern in NOT_APPROVED_PATTERNS:
        installed = packages.get(pkg)
        if installed and re.match(pattern, installed):
            violations.append(f"{pkg}=={installed} matches NOT-APPROVED pattern {pattern}")

    return violations

def main():
    violations = check_python_version() + check_pip_packages()
    if violations:
        print("VERSION POLICY VIOLATIONS — deployment blocked:")
        for v in violations:
            print(f"  ✗ {v}")
        sys.exit(1)
    else:
        print("Version policy check passed.")

if __name__ == "__main__":
    main()

# agents/version_inventory.py
# Runs on inference nodes via scheduled cron; reports to inventory service
import subprocess, json, socket, os, sys
from datetime import datetime, timezone

def collect_python_packages() -> dict:
    result = subprocess.run(
        ["pip", "list", "--format=json"],
        capture_output=True, text=True
    )
    return {p["name"].lower(): p["version"] for p in json.loads(result.stdout)}

def collect_system_info() -> dict:
    info = {
        "python_version": f"{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}",
        "hostname": socket.gethostname(),
        "service": os.environ.get("SERVICE_NAME", "unknown"),
        "environment": os.environ.get("DEPLOY_ENV", "unknown"),
        "collected_at": datetime.now(timezone.utc).isoformat(),
    }
    try:
        import torch
        info["cuda_version"] = torch.version.cuda
        info["pytorch_version"] = torch.__version__
    except ImportError:
        info["cuda_version"] = None
        info["pytorch_version"] = None
    return info

def report_to_inventory(payload: dict) -> None:
    import urllib.request
    req = urllib.request.Request(
        os.environ["VERSION_INVENTORY_URL"],
        data=json.dumps(payload).encode(),
        headers={"Content-Type": "application/json",
                 "Authorization": f"Bearer {os.environ['VERSION_INVENTORY_TOKEN']}"},
        method="POST",
    )
    urllib.request.urlopen(req, timeout=10)

if __name__ == "__main__":
    payload = {**collect_system_info(), "packages": collect_python_packages()}
    report_to_inventory(payload)
    print(f"Reported {len(payload['packages'])} packages for {payload['hostname']}")

# services/policy_evaluator.py
# Runs against collected inventory snapshots to surface drift

APPROVED_MATRIX = {
    "torch": {"approved": ["2.3", "2.4"], "deprecated": ["2.1", "2.2"]},
    "langchain": {"approved": ["0.2"], "deprecated": ["0.1"]},
    "openai": {"approved": None},          # None = all current; flag 0.x only
    "python_version": {"approved": ["3.11", "3.12"], "deprecated": ["3.10"]},
}

def evaluate_snapshot(snapshot: dict) -> list[dict]:
    violations = []
    packages = snapshot.get("packages", {})

    for pkg, policy in APPROVED_MATRIX.items():
        if pkg == "python_version":
            installed = ".".join(snapshot.get("python_version", "").split(".")[:2])
        else:
            installed = packages.get(pkg)
        if not installed:
            continue

        installed_minor = ".".join(installed.split(".")[:2])
        approved = policy.get("approved")
        deprecated = policy.get("deprecated", [])

        if approved is not None and installed_minor not in approved and installed_minor not in (deprecated or []):
            violations.append({
                "package": pkg,
                "installed": installed,
                "severity": "CRITICAL",
                "reason": "not-approved version detected in production",
            })
        elif deprecated and installed_minor in deprecated:
            violations.append({
                "package": pkg,
                "installed": installed,
                "severity": "WARNING",
                "reason": "deprecated version — upgrade required",
            })

    return violations
